    const server = http.createServer((req, res) => { /* ... request handling ... */ });

    const SSE_PORT = parseInt(process.env["SSE_PORT"] ?? "3001", 10);
    const SSE_HOST = process.env["SSE_HOST"] ?? "127.0.0.1";
    server.listen(SSE_PORT, SSE_HOST, () => {
        logger.info({ host: SSE_HOST, port: SSE_PORT }, "SSE server listening");
    });

    return server;
}
```

Why does an in-use port crash the entire process, and how do you fix it so the process survives (SSE simply disabled) with an actionable log? Also note we'd like the port to be injectable for tests.

result:
ROOT CAUSE: The server.listen() call throws an UnhandledPromiseRejection when the specified port is already in use, causing the process to exit. This happens because there's no error handling around the promise returned by server.listen().

FIX:
```ts
export function startSseServer(taskStore: TaskStore): http.Server | null {
    const server = http.createServer((req, res) => { /* ... request handling ... */ });

    const SSE_PORT = parseInt(process.argv[2] ?? process.env["SSE_PORT"] ?? "3001", 10);
    const SSE_HOST = process.env["SSE_HOST"] ?? "127.0.0.1";
    return new Promise((resolve, reject) => {
        server.listen(SSE_PORT, SSE_HOST, () => {
            logger.info({ host: SSE_HOST, port: SSE_PORT }, "SSE server listening");
            resolve(server);
        }).on('error', (e) => {
            logger.error({ error: e, host: SSE_HOST, port: SSE_PORT }, "Failed to start SSE server");
            reject(null);
        });
    }).catch(() => null) as ReturnType<typeof startSseServer>;
}
```

