result:
ROOT CAUSE:
`http.Server` emits an `"error"` event when `listen()` fails (e.g., `EADDRINUSE`). Because no `"error"` listener is attached to the server, Node.js promotes it to an uncaught exception, killing the entire process—including the unrelated stdio MCP server.

FIX:

```ts
// streaming/sse-server.ts
import http from "node:http";
import { logger } from "../logger.js";

export function startSseServer(
  taskStore: TaskStore,
  port: number = parseInt(process.env["SSE_PORT"] ?? "3001", 10),
  host: string = process.env["SSE_HOST"] ?? "127.0.0.1",
): http.Server | null {
  const server = http.createServer((req, res) => {
    // ... routes GET /tasks/:id/stream ...
  });

  server.on("error", (err: NodeJS.ErrnoException) => {
    // SSE is optional — log and continue; stdio MCP server is unaffected.
    logger.warn(
      { err: err.message, code: err.code, host, port },
      "SSE server failed to bind — streaming unavailable",
    );
    // Do NOT rethrow; let the process keep running.
  });

  server.listen(port, host, () => {
    logger.info({ host, port }, "SSE server listening");
  });

  return server;
}
```

```ts
// index.ts
